const currentDate = ($currentDate || '').toString().trim() || new Date().toISOString().slice(0, 10);
const subjectPrefix = ($flow.state.subjectPrefix || 'Nightly Email Summary').toString().trim();
const summaryRecipient = ($flow.state.summaryRecipient || '').toString().trim();
const lookbackDays = Number(($flow.state.lookbackDays || '1').toString()) || 1;
const defaultQuery = `newer_than:${lookbackDays}d in:inbox -category:promotions -category:social -in:sent -in:drafts -in:spam -in:trash`;
const gmailQuery = (($flow.state.gmailQuery || '').toString().trim()) || defaultQuery;
const summarySubject = `${subjectPrefix} - ${currentDate}`;
return {
  summaryDateLabel: currentDate,
  summarySubject,
  summaryRecipientResolved: summaryRecipient,
  gmailQuery
};

const raw = $gmailMessagesRaw;
if (typeof raw === 'string') return raw;
try {
  return JSON.stringify(raw, null, 2);
} catch (error) {
  return String(raw ?? '');
}
